dashboard.definition:
{
  "title": "Source - Sysmon",
  "description": "Windows Sysmon — threat hunting with process creation, network connections, and file change forensics",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Sysmon Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" by _time span=1h"
      }
    },
    "ds_process_creates": {
      "type": "ds.search",
      "name": "Process Creates",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" EventCode=1 | stats count"
      }
    },
    "ds_network_connections": {
      "type": "ds.search",
      "name": "Network Connections",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" EventCode=3 | stats count"
      }
    },
    "ds_file_creates": {
      "type": "ds.search",
      "name": "File Creates",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" EventCode=11 | stats count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Events Over Time by EventCode",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" | eval event_label=case(EventCode=1,\"1-ProcessCreate\", EventCode=3,\"3-NetworkConnect\", EventCode=5,\"5-ProcessTerminate\", EventCode=7,\"7-ImageLoaded\", EventCode=10,\"10-ProcessAccess\", EventCode=11,\"11-FileCreate\", EventCode=12,\"12-RegistryAdd\", EventCode=13,\"13-RegistrySet\", EventCode=22,\"22-DNSQuery\", 1=1, tostring(EventCode)) | timechart span=1h count by event_label limit=8"
      }
    },
    "ds_event_type_pie": {
      "type": "ds.search",
      "name": "Events by Event Type",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" EventCode=* | eval event_label=case(EventCode=1,\"1 - Process Create\", EventCode=3,\"3 - Network Connect\", EventCode=5,\"5 - Process Terminate\", EventCode=7,\"7 - Image Loaded\", EventCode=10,\"10 - Process Access\", EventCode=11,\"11 - File Create\", EventCode=12,\"12 - Registry Add/Delete\", EventCode=13,\"13 - Registry Set\", EventCode=22,\"22 - DNS Query\", 1=1, tostring(EventCode)) | stats count by event_label | sort -count"
      }
    },
    "ds_top_processes": {
      "type": "ds.search",
      "name": "Top Processes",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" EventCode=1 Image=* | stats count by Image | sort -count | head 15 | rename Image as \"Process\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:WinEventLog:Sysmon\" | table _time host EventCode Image CommandLine | sort -_time | head 30 | rename EventCode as \"Event ID\" CommandLine as \"Command Line\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Sysmon\n\n**Sourcetype:** `FAKE:WinEventLog:Sysmon` | **Coverage:** Process creation, network connections, file/registry changes on Windows servers | **Format:** XML\n\n**Why monitor?** Threat hunting essential -- track process creation chains, outbound network connections, and file system changes to detect malware, lateral movement, and persistence mechanisms.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_process_creates": {
      "type": "splunk.singlevalue",
      "title": "Process Creates (ID 1)",
      "dataSources": { "primary": "ds_process_creates" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_network_connections": {
      "type": "splunk.singlevalue",
      "title": "Network Connections (ID 3)",
      "dataSources": { "primary": "ds_network_connections" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_file_creates": {
      "type": "splunk.singlevalue",
      "title": "File Creates (ID 11)",
      "dataSources": { "primary": "ds_file_creates" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Events Over Time by EventCode",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#53A051", "#00D2FF", "#DC4E41", "#F8BE34", "#7B56DB", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_event_type_pie": {
      "type": "splunk.pie",
      "title": "Events by Event Type",
      "dataSources": { "primary": "ds_event_type_pie" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#00CDAF"]
      }
    },
    "viz_top_processes": {
      "type": "splunk.bar",
      "title": "Top Processes (EventCode=1)",
      "dataSources": { "primary": "ds_top_processes" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Executions",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Events",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_process_creates", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_network_connections", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_file_creates", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 750, "h": 350 } },
      { "item": "viz_event_type_pie", "type": "block", "position": { "x": 750, "y": 270, "w": 450, "h": 350 } },
      { "item": "viz_top_processes", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
